                                .value
                                .toString()

                        val role =
                            snapshot.child("role")
                                .value
                                .toString()

                        txtWelcome.text =
                            "Selamat datang, $shortName"

                        txtRole.text =
                            role
                    }

                    override fun onCancelled(
                        error: DatabaseError
                    ) {

                    }
                }
            )
    }

    override fun onDestroyView() {
        super.onDestroyView()

        handler.removeCallbacksAndMessages(null)
    }
}

package com.possaas.Kasir
import android.content.Intent import android.os.Bundle import android.os.Handler import android.os.Looper import android.view.LayoutInflater import android.view.View import android.view.ViewGroup import android.widget.LinearLayout import android.widget.TextView import androidx.fragment.app.Fragment import com.google.firebase.auth.FirebaseAuth import com.google.firebase.database.FirebaseDatabase import com.possaas.FiturKasir.PilihMenu.PilihMenuActivity import com.possaas.FiturKasir.Dialogs.TablePickerDialog import android.widget.Toast import com.possaas.R import android.app.Dialog import android.view.Window import android.widget.FrameLayout import android.widget.ImageView import java.text.SimpleDateFormat import java.util.Date import java.util.Locale
class HomeKasirFragment : Fragment() {
private lateinit var txtWelcome: TextView private lateinit var txtRole: TextView private lateinit var txtStatus: TextView private lateinit var txtDate: TextView private lateinit var txtHour: TextView private lateinit var txtMinute: TextView private lateinit var txtSecond: TextView
private val handler = Handler(Looper.getMainLooper())
override fun onCreateView( inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle? ): View {
val view = inflater.inflate( R.layout.fragment_home_kasir, container, false )
txtWelcome = view.findViewById(R.id.txtWelcome)
txtRole = view.findViewById(R.id.txtRole)
txtStatus = view.findViewById(R.id.txtStatus) txtStatus.setOnClickListener { showStatusDialog() }
txtDate = view.findViewById(R.id.txtDate)
txtHour = view.findViewById(R.id.txtHour)
txtMinute = view.findViewById(R.id.txtMinute)
txtSecond = view.findViewById(R.id.txtSecond)
// ACTION PILIH MENU view.findViewById<LinearLayout>(R.id.btnPilihMenu).setOnClickListener { startActivity(Intent(requireContext(), PilihMenuActivity::class.java)) }
// ACTION MANAJEMEN MEJA view.findViewById<LinearLayout>(R.id.btnManajemenMeja).setOnClickListener { val picker = TablePickerDialog(requireContext(), TablePickerDialog.Mode.MANAGE_TABLES, emptySet()) { selected -> // selected contains tables marked as occupied; show simple feedback if (selected.isEmpty()) { Toast.makeText(requireContext(), "Tidak ada meja dipilih", Toast.LENGTH_SHORT).show() } else { Toast.makeText(requireContext(), "Meja dipilih: ${selected.joinToString(", ")}", Toast.LENGTH_SHORT).show() } } picker.show() }
// ACTION RIWAYAT TRANSAKSI view.findViewById<LinearLayout>(R.id.btnRiwayatTransaksi).setOnClickListener { val intent = Intent(requireContext(), Class.forName("com.possaas.FiturKasir.TransactionHistory.TransactionHistoryActivity")) startActivity(intent) }
loadUserData()
startRealtimeClock()
return view }
private fun showStatusDialog() {
val dlg = Dialog(requireContext()) dlg.requestWindowFeature(Window.FEATURE_NO_TITLE) dlg.setCancelable(true) val layout = layoutInflater.inflate(R.layout.dialog_shop_status, null)
// close button was moved to top-end outside inner header; use btnClose val btnClose = layout.findViewById<LinearLayout>(R.id.btnClose) val cardBuka = layout.findViewById<LinearLayout>(R.id.cardBuka) val cardTutup = layout.findViewById<LinearLayout>(R.id.cardTutup) val tvBuka = layout.findViewById<TextView>(R.id.tvBuka) val tvTutup = layout.findViewById<TextView>(R.id.tvTutup)
btnClose.setOnClickListener { dlg.dismiss() }
cardBuka.setOnClickListener { txtStatus.text = "BUKA " dlg.dismiss() }
cardTutup.setOnClickListener { txtStatus.text = "TUTUP " dlg.dismiss() }
dlg.setContentView(layout) dlg.show() }
private fun loadUserData() {
val uid = FirebaseAuth.getInstance() .currentUser?.uid ?: return
FirebaseDatabase .getInstance() .getReference("users") .child(uid) .get() .addOnSuccessListener {
val shortName = it.child("short_name") .value .toString()
val role = it.child("role") .value .toString()
txtWelcome.text = "Selamat datang, $shortName"
txtRole.text = role } }
private fun startRealtimeClock() {
handler.post(object : Runnable {
override fun run() {
val date = SimpleDateFormat( "dd MMMM yyyy", Locale("id", "ID") ).format(Date())
txtDate.text = date
txtHour.text = SimpleDateFormat( "HH", Locale.getDefault() ).format(Date())
txtMinute.text = SimpleDateFormat( "mm", Locale.getDefault() ).format(Date())
txtSecond.text = SimpleDateFormat( "ss", Locale.getDefault() ).format(Date())
handler.postDelayed( this, 1000 ) } }) } }

package com.possaas.Kasir
import android.content.Intent import android.os.Bundle import android.os.Handler import android.os.Looper import android.view.LayoutInflater import android.view.View import android.view.ViewGroup import android.widget.LinearLayout import android.widget.TextView import androidx.fragment.app.Fragment import com.google.firebase.auth.FirebaseAuth import com.google.firebase.database.FirebaseDatabase import com.possaas.FiturKasir.PilihMenu.PilihMenuActivity import com.possaas.FiturKasir.Dialogs.TablePickerDialog import android.widget.Toast import com.possaas.R import android.app.Dialog import android.view.Window import android.widget.FrameLayout import android.widget.ImageView import java.text.SimpleDateFormat import java.util.Date import java.util.Locale
class HomeKasirFragment : Fragment() {
private lateinit var txtWelcome: TextView private lateinit var txtRole: TextView private lateinit var txtStatus: TextView private lateinit var txtDate: TextView private lateinit var txtHour: TextView private lateinit var txtMinute: TextView private lateinit var txtSecond: TextView
private val handler = Handler(Looper.getMainLooper())
override fun onCreateView( inflater: LayoutInflater, container: ViewGroup?, savedInstanceState: Bundle? ): View {
val view = inflater.inflate( R.layout.fragment_home_kasir, container, false )
txtWelcome = view.findViewById(R.id.txtWelcome)
txtRole = view.findViewById(R.id.txtRole)
txtStatus = view.findViewById(R.id.txtStatus) txtStatus.setOnClickListener { showStatusDialog() }
txtDate = view.findViewById(R.id.txtDate)
txtHour = view.findViewById(R.id.txtHour)
txtMinute = view.findViewById(R.id.txtMinute)
txtSecond = view.findViewById(R.id.txtSecond)
// ACTION PILIH MENU view.findViewById<LinearLayout>(R.id.btnPilihMenu).setOnClickListener { startActivity(Intent(requireContext(), PilihMenuActivity::class.java)) }
// ACTION MANAJEMEN MEJA view.findViewById<LinearLayout>(R.id.btnManajemenMeja).setOnClickListener { val picker = TablePickerDialog(requireContext(), TablePickerDialog.Mode.MANAGE_TABLES, emptySet()) { selected -> // selected contains tables marked as occupied; show simple feedback if (selected.isEmpty()) { Toast.makeText(requireContext(), "Tidak ada meja dipilih", Toast.LENGTH_SHORT).show() } else { Toast.makeText(requireContext(), "Meja dipilih: ${selected.joinToString(", ")}", Toast.LENGTH_SHORT).show() } } picker.show() }
// ACTION RIWAYAT TRANSAKSI view.findViewById<LinearLayout>(R.id.btnRiwayatTransaksi).setOnClickListener { val intent = Intent(requireContext(), Class.forName("com.possaas.FiturKasir.TransactionHistory.TransactionHistoryActivity")) startActivity(intent) }
loadUserData()
startRealtimeClock()
return view }
private fun showStatusDialog() {
val dlg = Dialog(requireContext()) dlg.requestWindowFeature(Window.FEATURE_NO_TITLE) dlg.setCancelable(true) val layout = layoutInflater.inflate(R.layout.dialog_shop_status, null)
// close button was moved to top-end outside inner header; use btnClose val btnClose = layout.findViewById<LinearLayout>(R.id.btnClose) val cardBuka = layout.findViewById<LinearLayout>(R.id.cardBuka) val cardTutup = layout.findViewById<LinearLayout>(R.id.cardTutup) val tvBuka = layout.findViewById<TextView>(R.id.tvBuka) val tvTutup = layout.findViewById<TextView>(R.id.tvTutup)
btnClose.setOnClickListener { dlg.dismiss() }
cardBuka.setOnClickListener { txtStatus.text = "BUKA " dlg.dismiss() }
cardTutup.setOnClickListener { txtStatus.text = "TUTUP " dlg.dismiss() }
dlg.setContentView(layout) // Remove default dialog window background so overlay and rounded corners render correctly dlg.window?.setBackgroundDrawableResource(android.R.color.transparent) dlg.show() }
private fun loadUserData() {
val uid = FirebaseAuth.getInstance() .currentUser?.uid ?: return
FirebaseDatabase .getInstance() .getReference("users") .child(uid) .get() .addOnSuccessListener {
val shortName = it.child("short_name") .value .toString()
val role = it.child("role") .value .toString()
txtWelcome.text = "Selamat datang, $shortName"
txtRole.text = role } }
private fun startRealtimeClock() {
handler.post(object : Runnable {
override fun run() {
val date = SimpleDateFormat( "dd MMMM yyyy", Locale("id", "ID") ).format(Date())
txtDate.text = date
txtHour.text = SimpleDateFormat( "HH", Locale.getDefault() ).format(Date())
txtMinute.text = SimpleDateFormat( "mm", Locale.getDefault() ).format(Date())
txtSecond.text = SimpleDateFormat( "ss", Locale.getDefault() ).format(Date())
handler.postDelayed( this, 1000 ) } }) } }

package com.possaas.Onboarding

import android.content.Intent
import android.graphics.Color
import android.os.*
import android.view.View
import android.view.WindowManager
import android.widget.Button
import android.widget.LinearLayout
import androidx.appcompat.app.AppCompatActivity
import androidx.viewpager2.widget.ViewPager2
import com.possaas.Role.RoleActivity
import com.possaas.R

class OnboardingActivity : AppCompatActivity() {

    private lateinit var viewPager:
            ViewPager2

    private lateinit var dotsLayout:
            LinearLayout

    private lateinit var handler:
            Handler

    private val delay = 8000L

    override fun onCreate(
        savedInstanceState: Bundle?
    ) {

        super.onCreate(savedInstanceState)

        // TRANSPARENT STATUS BAR
        window.decorView.systemUiVisibility =
            View.SYSTEM_UI_FLAG_LAYOUT_STABLE or
                    View.SYSTEM_UI_FLAG_LAYOUT_FULLSCREEN

        window.statusBarColor =
            Color.TRANSPARENT

        // FULL LAYOUT
        window.setFlags(
            WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS,
            WindowManager.LayoutParams.FLAG_LAYOUT_NO_LIMITS
        )

        setContentView(
            R.layout.activity_onboarding
        )

        viewPager =
            findViewById(R.id.viewPager)

        dotsLayout =
            findViewById(R.id.layoutDots)

        val btnMasuk =
            findViewById<Button>(R.id.btnMasuk)

        btnMasuk.setOnClickListener {

            startActivity(
                Intent(
                    this,
                    RoleActivity::class.java
                )
            )

            overridePendingTransition(
                R.anim.slide_in_right,
                R.anim.slide_out_left
            )

            finish()
        }

        val list = listOf(

            OnboardingItem(
                R.drawable.slide1,
                "Pilih Menu",
                "Kasir memilih menu yang dipesan pelanggan\n" +
                        "dan menambahkannya ke daftar pesanan."
            ),

            OnboardingItem(
                R.drawable.slide2,
                "Proses Pembayaran",
                "Kasir memproses pembayaran\n" +
                        "sesuai metode yang dipilih\n" +
                        "dan memastikan total transaksi sesuai."
            ),

            OnboardingItem(
                R.drawable.slide3,
                "Hasil Pembayaran",
                "Sistem menampilkan hasil pembayaran\n" +
                        "sebagai bukti transaksi\n" +
                        "yang telah berhasil dilakukan."
            )

        )

        viewPager.adapter =
            OnboardingAdapter(list)

        setupDots(
            list.size,
            0
        )

        viewPager.registerOnPageChangeCallback(
            object : ViewPager2.OnPageChangeCallback() {

                override fun onPageSelected(
                    position: Int
                ) {

                    setupDots(
                        list.size,
                        position
                    )
                }
            }
        )

        handler =
            Handler(Looper.getMainLooper())

        val runnable =
            object : Runnable {

                override fun run() {

                    val next =
                        if (
                            viewPager.currentItem ==
                            list.size - 1
                        ) 0
                        else
                            viewPager.currentItem + 1

                    viewPager.setCurrentItem(
                        next,
                        true
                    )

                    handler.postDelayed(
                        this,
                        delay
                    )
                }
            }

        handler.postDelayed(
            runnable,
            delay
        )
    }

    private fun setupDots(
        count: Int,
        position: Int
    ) {

        dotsLayout.removeAllViews()

        for (i in 0 until count) {

            val dot = View(this)

            val params =
                LinearLayout.LayoutParams(
                    18,
                    18
                )

            params.setMargins(
                8,
                0,
                8,
                0
            )

            dot.layoutParams = params

            dot.setBackgroundResource(
                if (i == position)
                    R.drawable.dot_active
                else
                    R.drawable.dot_inactive
            )

            dotsLayout.addView(dot)
        }
    }

    override fun onBackPressed() {
        super.onBackPressed()
    }
}

